module DAC8Bit (
    input [7:0] data_in,
    output reg [9:0] voltage_out
);
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    parameter V_REF = 5; // Reference voltage

    always @(*) begin
        voltage_out = (data_in * 1023) / 255; // Convert 8-bit input to 10-bit output
    end
endmodule
